  .slide-gap { background: var(--bg-dark); }
  .slide-gap .slide-label { color: var(--accent-cyan); }
  .slide-gap .gap-scenario {
    display: flex;
    gap: 28px;
    margin-bottom: 28px;
  }
  .slide-gap .gap-card {
    flex: 1;
    min-width: 0;
    background: var(--bg-card);
    border-radius: 16px;
    padding: 32px;
    border-top: 3px solid;
  }
  .slide-gap .gap-card h3 {
    font-size: 18px;
    font-weight: 700;
    letter-spacing: 1.5px;
    text-transform: uppercase;
    margin-bottom: 20px;
  }
  .slide-gap .gap-step {
    display: flex;
    gap: 14px;
    align-items: flex-start;
    padding: 14px 0;
    border-bottom: 1px solid rgba(51,65,85,0.5);
    font-size: 20px;
    color: var(--text-secondary);
    line-height: 1.5;
  }
  .slide-gap .gap-step:last-child { border-bottom: none; }
  .slide-gap .gap-step .gap-icon { font-size: 24px; flex-shrink: 0; }
  .slide-gap .gap-insight {
    background: rgba(6,182,212,0.08);
    border: 1px solid rgba(6,182,212,0.25);
    border-radius: 16px;
    padding: 32px 36px;
    font-size: 24px;
    font-weight: 500;
    color: var(--text-primary);
    line-height: 1.6;
  }

  /* ════════════════════════════════════════════════════ */
  /* SLIDE: STAYING ON EDGE (inserted after slide 5)    */
  /* ════════════════════════════════════════════════════ */
  .slide-wave { background: var(--bg-dark); }
  .slide-wave .slide-label { color: var(--accent-amber); }
